DROP TABLE IF EXISTS `INVENTORY`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `INVENTORY` (
  `Inventory_ID` int(11) NOT NULL AUTO_INCREMENT,
  `NDC` varchar(10) DEFAULT NULL,
  `InStockQuantity` int(11) DEFAULT NULL,
  `ReorderLevel` int(11) DEFAULT NULL,
  `LastRestockDate` date DEFAULT curdate(),
  `StorageLocation` varchar(50) DEFAULT 'Not Downstacked',
  PRIMARY KEY (`Inventory_ID`),
  KEY `NDC` (`NDC`),
  CONSTRAINT `INVENTORY_ibfk_1` FOREIGN KEY (`NDC`) REFERENCES `PRODUCT` (`NDC`)
) ENGINE=InnoDB AUTO_INCREMENT=9986 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

